private async executeOnAll(
  operation: (channel: Channel) => Promise<void>
): Promise<Map<ChannelPlatform, ChannelOperationResult>> {
  const results = new Map<ChannelPlatform, ChannelOperationResult>()
  const promises = [...this.entries.entries()].map(async ([platform, entry]) => {
    try {
      await operation(entry.channel)
      results.set(platform, { success: true })
    } catch (error) {
      results.set(platform, {
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      })
    }
  })
  await Promise.all(promises)
  return results
}

async connectAll() { return this.executeOnAll(ch => ch.connect()) }
async disconnectAll() { return this.executeOnAll(ch => ch.disconnect()) }

WHY: Eliminates 18 lines of near-identical code. The extracted helper clearly communicates the shared pattern (run an operation on all channels, collect results). Both public methods become one-liners.

