private parseMessage(msg: BaileysMessage): IncomingMessage | null {
  if (msg.key.fromMe) return null
  if (!msg.message) return null
  const text = msg.message.conversation ?? msg.message.extendedTextMessage?.text ?? ''
  if (!text) return null
  return {
    id: msg.key.id,
    platform: 'whatsapp',
    channelId: msg.key.remoteJid,
    senderId: msg.key.remoteJid,
    text,
    timestamp: new Date((msg.messageTimestamp ?? 0) * 1000),
    raw: msg,
  }
}

private setupEventHandlers(): void {
  if (!this.socket) return
  this.socket.ev.on('messages.upsert', (data: unknown) => {
    const event = data as BaileysUpsertEvent
    for (const msg of event.messages) {
      const parsed = this.parseMessage(msg)
      if (parsed) {
        for (const handler of this.messageHandlers) { handler(parsed) }
      }
    }
  })
}

WHY: Extracting parseMessage reduces max nesting from 4 to 3 levels, separates message parsing (pure logic) from event wiring (imperative shell), and makes the parsing independently testable.

